app.get('/orders', async (req, res) => {
  const { cursor, limit = 20 } = req.query;
  const orders = await db.orders.findMany({ cursor, take: Math.min(limit, 100) + 1 });
  const hasMore = orders.length > limit;
  return res.json({ data: orders.slice(0, limit), hasMore, nextCursor: hasMore ? orders[limit - 1].id : null });
});

